from typing import Optional

def inorder_successor(root: Optional['TreeNode'], p: 'TreeNode') -> Optional['TreeNode']:
    successor = None
    while root:
        if p.val >= root.val:
            root = root.right
        else:
            successor = root
            root = root.left
    return successor
